// Compute current month info for file paths and prompts
const now = new Date();
const year = now.getFullYear().toString();
const month = String(now.getMonth() + 1).padStart(2, '0');
const monthName = now.toLocaleString('en-US', { month: 'long' });
// Send date: 3rd of the month
const sendDate = `${year}-${month}-03`;

return {
  json: {
    year,
    month,
    monthName,
    monthYear: `${monthName} ${year}`,
    sendDate,
    obsidianPath: `StPeteMusic/newsletters/${year}/${month}-newsletter.md`,
    newsletterTitle: `St Pete Music Newsletter - ${monthName} ${year}`
  }
};

// Combine PostSchedule + IG_PastPosts into a single structured prompt context.
// The merge node passes both sheet results — index 0 = PostSchedule, index 1 = IG_PastPosts.
// We grab all items and separate them by their source.

// Get context from Get Month Info node
const monthCtx = $('Get Month Info').first().json;

// PostSchedule rows (all items from first Merge input)
const scheduleRows = $('Read PostSchedule').all().map(i => i.json);

// IG_PastPosts rows
const igRows = $('Read IG_PastPosts').all().map(i => i.json);

// Format PostSchedule as readable text
const scheduleText = scheduleRows.length > 0
  ? scheduleRows
      .map(r => Object.entries(r).map(([k, v]) => `${k}: ${v}`).join(' | '))
      .join('\n')
  : 'No upcoming events data available.';

// Format recent IG posts (last 10)
const igText = igRows.length > 0
  ? igRows
      .slice(-10)
      .map(r => Object.entries(r).map(([k, v]) => `${k}: ${v}`).join(' | '))
      .join('\n')
  : 'No recent IG post data available.';

const prompt = `You are drafting the monthly newsletter for StPeteMusic for ${monthCtx.monthYear}.

Here is the upcoming event/post schedule data (PostSchedule sheet):
${scheduleText}

Here are recent Instagram post records for the Social Roundup section (IG_PastPosts sheet):
${igText}

Using the data above, write the full newsletter body HTML following your style guidelines.
Focus on Suite E Studios events. For the Social Roundup, pick 2-3 of the most recent IG/YouTube posts.
Remember: output ONLY the four-section HTML body. No extra text or markdown fences.`;

return {
  json: {
    ...monthCtx,
    prompt
  }
};
